import{_ as e,o as l,c as i,a2 as o}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),t={name:"guide/faq.md"};function r(n,a,h,s,d,c){return l(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="启动问题" tabindex="-1">启动问题 <a class="header-anchor" href="#启动问题" aria-label="Permalink to &quot;启动问题&quot;">​</a></h2><h3 id="双击-exe-无反应" tabindex="-1">双击 exe 无反应 <a class="header-anchor" href="#双击-exe-无反应" aria-label="Permalink to &quot;双击 exe 无反应&quot;">​</a></h3><ol><li>检查是否已安装 .NET 10 Desktop Runtime</li><li>以管理员身份运行</li><li>检查杀毒软件是否拦截</li></ol><h3 id="提示缺少-net-运行时" tabindex="-1">提示缺少 .NET 运行时 <a class="header-anchor" href="#提示缺少-net-运行时" aria-label="Permalink to &quot;提示缺少 .NET 运行时&quot;">​</a></h3><p>从 <a href="https://dotnet.microsoft.com/download/dotnet/10.0" target="_blank" rel="noreferrer">Microsoft 官网</a> 下载并安装 .NET 10 Desktop Runtime。</p><h2 id="工具管理" tabindex="-1">工具管理 <a class="header-anchor" href="#工具管理" aria-label="Permalink to &quot;工具管理&quot;">​</a></h2><h3 id="工具不显示" tabindex="-1">工具不显示 <a class="header-anchor" href="#工具不显示" aria-label="Permalink to &quot;工具不显示&quot;">​</a></h3><ol><li>确认工具文件在 <code>tools/</code> 目录下</li><li>检查文件扩展名是否为 <code>.exe</code>、<code>.lnk</code> 或 <code>.bat</code></li><li>重新进入对应分类页面</li></ol><h3 id="如何添加自定义工具" tabindex="-1">如何添加自定义工具 <a class="header-anchor" href="#如何添加自定义工具" aria-label="Permalink to &quot;如何添加自定义工具&quot;">​</a></h3><p>将工具文件放入 <code>tools/</code> 目录下的对应分类文件夹中，或在 设置 → 工具管理 中导入 JSON 配置。</p><h2 id="代理工具" tabindex="-1">代理工具 <a class="header-anchor" href="#代理工具" aria-label="Permalink to &quot;代理工具&quot;">​</a></h2><h3 id="代理工具不见了" tabindex="-1">代理工具不见了 <a class="header-anchor" href="#代理工具不见了" aria-label="Permalink to &quot;代理工具不见了&quot;">​</a></h3><ol><li>检查 <code>ProxyTools/mihomo/mihomo.exe</code> 是否存在</li><li>如不存在，在工具商店重新安装</li><li>如存在但仍不显示，重启应用</li></ol><h3 id="代理无法启动" tabindex="-1">代理无法启动 <a class="header-anchor" href="#代理无法启动" aria-label="Permalink to &quot;代理无法启动&quot;">​</a></h3><ol><li>检查端口 7890 和 9097 是否被占用</li><li>检查配置文件格式</li><li>查看日志文件</li></ol><h3 id="系统代理未生效" tabindex="-1">系统代理未生效 <a class="header-anchor" href="#系统代理未生效" aria-label="Permalink to &quot;系统代理未生效&quot;">​</a></h3><ol><li>检查 Windows 设置 → 网络和 Internet → 代理</li><li>确认代理已启动（状态指示灯为绿色）</li><li>尝试重启代理</li></ol><h2 id="下载问题" tabindex="-1">下载问题 <a class="header-anchor" href="#下载问题" aria-label="Permalink to &quot;下载问题&quot;">​</a></h2><h3 id="插件下载失败" tabindex="-1">插件下载失败 <a class="header-anchor" href="#插件下载失败" aria-label="Permalink to &quot;插件下载失败&quot;">​</a></h3><ol><li>检查网络连接</li><li>在 设置 → 更新 → 下载代理 中配置加速代理</li><li>尝试手动下载 <code>ProxyTools.zip</code> 并解压到应用目录</li></ol><h3 id="下载速度慢" tabindex="-1">下载速度慢 <a class="header-anchor" href="#下载速度慢" aria-label="Permalink to &quot;下载速度慢&quot;">​</a></h3><ol><li>配置 GitHub 加速代理</li><li>使用 VPN 或代理工具</li><li>手动从 GitHub 下载</li></ol><h2 id="界面问题" tabindex="-1">界面问题 <a class="header-anchor" href="#界面问题" aria-label="Permalink to &quot;界面问题&quot;">​</a></h2><h3 id="毛玻璃效果不显示" tabindex="-1">毛玻璃效果不显示 <a class="header-anchor" href="#毛玻璃效果不显示" aria-label="Permalink to &quot;毛玻璃效果不显示&quot;">​</a></h3><ol><li>确认 Windows 版本为 Windows 11 或 Windows 10 1809+</li><li>检查系统设置中是否启用了透明效果</li><li>尝试切换主题</li></ol><h3 id="界面错乱" tabindex="-1">界面错乱 <a class="header-anchor" href="#界面错乱" aria-label="Permalink to &quot;界面错乱&quot;">​</a></h3><ol><li>尝试切换主题</li><li>重启应用</li><li>恢复默认设置</li></ol><h2 id="其他问题" tabindex="-1">其他问题 <a class="header-anchor" href="#其他问题" aria-label="Permalink to &quot;其他问题&quot;">​</a></h2><h3 id="配置文件在哪里" tabindex="-1">配置文件在哪里？ <a class="header-anchor" href="#配置文件在哪里" aria-label="Permalink to &quot;配置文件在哪里？&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%\\ToolboxWinUI\\</span></span>
<span class="line"><span>├── settings.json    # 应用设置</span></span>
<span class="line"><span>├── tools.json       # 工具配置</span></span>
<span class="line"><span>└── proxy/           # 代理配置</span></span></code></pre></div><h3 id="如何完全卸载" tabindex="-1">如何完全卸载？ <a class="header-anchor" href="#如何完全卸载" aria-label="Permalink to &quot;如何完全卸载？&quot;">​</a></h3><ol><li>删除应用目录</li><li>删除 <code>%APPDATA%\\ToolboxWinUI\\</code> 目录</li></ol>`,33)])])}const p=e(t,[["render",r]]);export{b as __pageData,p as default};
